<span class="line"><span style="color:#EBA0AC;font-style:italic;">    model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;anthropic/claude-sonnet-4-6&quot;</span><span style="color:#9399B2;">,</span></span>
